const inp = $input.first().json;
const chatInput = (inp.chatInput || '').trim();

// ── Guard: minimum length
if (chatInput.length < 10) {
  throw new Error('VALIDATION_ERROR: Clinical description too short (< 10 chars).');
}
// ── Guard: maximum length (prevent context overflow)
if (chatInput.length > 8000) {
  throw new Error('VALIDATION_ERROR: Input exceeds 8000 character limit. Please summarise.');
}

// ── Prompt injection heuristics
const injectionPatterns = [
  /ignore (all |previous |prior )?instructions/i,
  /you are now/i,
  /forget (everything|all)/i,
  /system:\s/i,
  /\[INST\]/,
  /###\s*(System|Human|Assistant)/i,
];
const injectionFlag = injectionPatterns.some(p => p.test(chatInput));

// ── Generate deterministic Case ID
const caseId = 'CASE-' + Date.now() + '-' +
  Math.random().toString(36).substr(2, 6).toUpperCase();

return [{
  json: {
    chatInput,
    sessionId: inp.sessionId || `sess_${Date.now()}`,
    caseId,
    timestamp:       new Date().toISOString(),
    inputCharCount:  chatInput.length,
    injectionFlag,
    pipelineVersion: 'MediSafe-MAS-v3'
  }
}];

