// NEWS2 Calculator — National Early Warning Score 2
// Input: JSON string with vital sign fields
const raw = $fromAI('vital_signs', 'JSON object with keys: rr (resp rate), spo2 (%), sbp (systolic mmHg), hr (heart rate), temp (celsius), gcs (15=normal), on_oxygen (bool)', 'string');
let params;
try { params = JSON.parse(raw); } catch(e) { return JSON.stringify({error: 'Invalid JSON input: ' + e.message}); }

let score = 0;
const notes = [];

const rr   = parseFloat(params.rr);
const spo2 = parseFloat(params.spo2);
const sbp  = parseFloat((params.sbp || '').toString().split('/')[0]);
const hr   = parseFloat(params.hr);
const temp = parseFloat(params.temp);
const gcs  = parseFloat(params.gcs ?? 15);
const o2   = params.on_oxygen || false;

if (!isNaN(rr)) {
  if (rr <= 8)       { score += 3; notes.push('RR<=8: +3'); }
  else if (rr <= 11) { score += 1; notes.push('RR 9-11: +1'); }
  else if (rr <= 20) { notes.push('RR 12-20: +0'); }
  else if (rr <= 24) { score += 2; notes.push('RR 21-24: +2'); }
  else               { score += 3; notes.push('RR>=25: +3'); }
}
if (!isNaN(spo2)) {
  if (spo2 <= 91)      { score += 3; notes.push('SpO2<=91: +3'); }
  else if (spo2 <= 93) { score += 2; notes.push('SpO2 92-93: +2'); }
  else if (spo2 <= 95) { score += 1; notes.push('SpO2 94-95: +1'); }
}
if (o2) { score += 2; notes.push('On supplemental O2: +2'); }
if (!isNaN(sbp)) {
  if (sbp <= 90)       { score += 3; notes.push('SBP<=90: +3'); }
  else if (sbp <= 100) { score += 2; notes.push('SBP 91-100: +2'); }
  else if (sbp <= 110) { score += 1; notes.push('SBP 101-110: +1'); }
  else if (sbp > 219)  { score += 3; notes.push('SBP>=220: +3'); }
}
if (!isNaN(hr)) {
  if (hr <= 40)       { score += 3; notes.push('HR<=40: +3'); }
  else if (hr <= 50)  { score += 1; notes.push('HR 41-50: +1'); }
  else if (hr <= 90)  { notes.push('HR 51-90: +0'); }
  else if (hr <= 110) { score += 1; notes.push('HR 91-110: +1'); }
  else if (hr <= 130) { score += 2; notes.push('HR 111-130: +2'); }
  else                { score += 3; notes.push('HR>=131: +3'); }
}
if (!isNaN(temp)) {
  if (temp <= 35.0)      { score += 3; notes.push('Temp<=35: +3'); }
  else if (temp <= 36.0) { score += 1; notes.push('Temp 35.1-36: +1'); }
  else if (temp <= 38.0) { notes.push('Temp 36.1-38: +0'); }
  else if (temp <= 39.0) { score += 1; notes.push('Temp 38.1-39: +1'); }
  else                   { score += 2; notes.push('Temp>=39.1: +2'); }
}
if (!isNaN(gcs) && gcs < 15) { score += 3; notes.push('GCS<15: +3'); }

const risk = score >= 7 ? 'HIGH — Immediate escalation' :
             score >= 5 ? 'MEDIUM — Urgent review within 30 min' :
             score >= 1 ? 'LOW — Increased monitoring' : 'MINIMAL';

return JSON.stringify({ news2_score: score, news2_risk: risk, scoring_breakdown: notes });

// HEART Score for chest pain risk stratification
const raw = $fromAI('heart_params', 'JSON with keys: history ("highly"|"moderately"|"slightly"), ecg ("normal"|"non-specific"|"lbbb_stemi"), age (number), risk_factors (number of: HTN, hypercholesterolaemia, DM, obesity, smoking, family history, atherosclerosis), troponin ("normal"|"1_3x"|"gt3x")', 'string');
let p;
try { p = JSON.parse(raw); } catch(e) { return JSON.stringify({error: 'Invalid JSON'}); }

const H = p.history === 'highly' ? 2 : p.history === 'moderately' ? 1 : 0;
const E = p.ecg === 'lbbb_stemi' ? 2 : p.ecg === 'non-specific' ? 1 : 0;
const A = p.age >= 65 ? 2 : p.age >= 45 ? 1 : 0;
const R = p.risk_factors >= 3 ? 2 : p.risk_factors >= 1 ? 1 : 0;
const T = p.troponin === 'gt3x' ? 2 : p.troponin === '1_3x' ? 1 : 0;

const score = H + E + A + R + T;
const risk  = score >= 7 ? 'HIGH (>50% MACE at 30d) — consider admit + early invasive'
            : score >= 4 ? 'MODERATE (12–17% MACE) — observe, serial troponins'
            : 'LOW (<2% MACE) — consider early discharge';

return JSON.stringify({
  heart_score: score,
  breakdown: {H, E, A, R, T},
  mace_risk: risk
});
